      const totalAssets = businesses.reduce((sum, b) => sum + parseFloat(b.revenue || "0"), 0) * 0.8;
      const currentAssets = totalAssets * 0.6;
      const fixedAssets = totalAssets * 0.4;

      const totalLiabilities = totalAssets * 0.3;
